chrome-devtools evaluate-script --function "() => {
  const tables = document.querySelectorAll('table.wikitable');
  const results = {};
  let currentYear = null;
  for (const table of tables) {
    const rows = table.querySelectorAll('tbody tr');
    for (const row of rows) {
      const cells = row.querySelectorAll('td, th');
      if (cells.length === 0) continue;
      const first = cells[0].innerText.trim();
      if (/^20[0-9]{2}$/.test(first)) {
        currentYear = first;
        if (!results[currentYear]) results[currentYear] = [];
        if (cells.length >= 3) {
          results[currentYear].push({name: cells[2].innerText.trim(), country: cells[3]?.innerText.trim()});
        }
      } else if (currentYear && cells.length >= 2 && !/^[0-9]+$/.test(first)) {
        // continuation row for same year (co-laureates)
        results[currentYear].push({name: cells[0].innerText.trim(), country: cells[1]?.innerText.trim()});
      }
    }
  }
  // return last 3 years
  const years = Object.keys(results).sort().slice(-3);
  return years.map(y => ({year: y, laureates: results[y]}));
}"

chrome-devtools evaluate-script --function "() => {
  const tables = document.querySelectorAll('table.wikitable');
  const allRows = [];
  for (const table of tables) {
    const rows = table.querySelectorAll('tbody tr');
    for (const row of rows) {
      const cells = row.querySelectorAll('td, th');
      const texts = Array.from(cells).map(c => c.innerText.trim());
      allRows.push(texts);
    }
  }
  // Find rows for 2023, 2024, 2025
  const years = ['2023','2024','2025'];
  const found = [];
  for (let i = 0; i < allRows.length; i++) {
    if (years.includes(allRows[i][0])) {
      found.push(allRows[i]);
      // grab continuation rows
      let j = i+1;
      while (j < allRows.length && allRows[j][0] === '') {
        found.push(allRows[j]);
        j++;
      }
    }
  }
  return found;
}"

